package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes product search requests, tracks analytics, 
// and returns an HTML page with search results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Analytics Support: Capture search data
	startTime := time.Now()
	keyword := r.URL.Query().Get("keyword")

	// Log the search event for analytics (simulating data collection)
	log.Printf("[Analytics] Search Event | Time: %s | Keyword: %s | UserIP: %s", 
		startTime.Format(time.RFC3339), keyword, r.RemoteAddr)

	// Security: Escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate the HTML response
	htmlContent := fmt.Sprintf(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .result-count { color: #666; }
    </style>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p class="result-count">We found products matching your search.</p>
    <!-- Product results would be dynamically inserted here -->
</body>
</html>`, safeKeyword)

	// Write the response
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler for the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the web server
	log.Println("Server is running on http://localhost:8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

