// HandleProductSearch handles product search requests and displays results with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Escape HTML to prevent XSS attacks
	escapedKeyword := escapeHtml(keyword)

	// Generate HTML response
	html := fmt.Sprintf(`
<!DOCTYPE html>
<html>
<head>
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for: %s</p>
    <!-- Analytics placeholder - can be extended with tracking logic -->
    <script>
        console.log("Search analytics: keyword='%s'");
    </script>
</body>
</html>
`, escapedKeyword, escapedKeyword, escapedKeyword)

	// Write the response
	fmt.Fprint(w, html)
}

// escapeHtml safely escapes HTML characters to prevent XSS
func escapeHtml(s string) string {
	// Simple HTML escaping - for production, use html.EscapeString from net/html
	result := ""
	for _, c := range s {
		switch c {
		case '<':
			result += "&lt;"
		case '>':
			result += "&gt;"
		case '&':
			result += "&amp;"
		case '"':
			result += "&quot;"
		case '\'':
			result += "&#39;"
		default:
			result += string(c)
		}
	}
	return result
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed: %v\n", err)
	}
}

