package main

import (
	"fmt"
	"html"
	"net/http"
	"os"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only accept GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	keyword := r.URL.Query().Get("keyword")
	// Escape the keyword to mitigate XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Set proper HTML content type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build and send the response
	response := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	w.Write([]byte(response))
}

func main() {
	// Register the handler for the "/search" endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Determine the listening port, default to 8080
	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	fmt.Printf("Starting server on :%s\n", port)
	if err := http.ListenAndServe(":"+port, nil); err != nil {
		fmt.Fprintf(os.Stderr, "Server error: %v\n", err)
		os.Exit(1)
	}
}

